import{_ as a,o as e,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const A=JSON.parse('{"title":"Apple Ads and Ad Attribution Kit","description":"","frontmatter":{"title":"Apple Ads and Ad Attribution Kit","slug":"apple-ads-and-ad-attribution-kit"},"headers":[],"relativePath":"account-hub/apple-ads-and-ad-attribution-kit.md","filePath":"account-hub/apple-ads-and-ad-attribution-kit.md"}'),r={name:"account-hub/apple-ads-and-ad-attribution-kit.md"};function n(s,t,l,p,d,c){return e(),o("div",null,[...t[0]||(t[0]=[i('<p>Branch now supports Ad Attribution Kit (AAK), Apple&#39;s successor to SKAdNetwork (SKAN), for Apple Ads campaigns.</p><p>AAK provides a modern attribution framework that will replace SKAdNetwork as iOS 26.2 rolls out to users. This is <strong>expected to happen mid-December 2025</strong>.</p><h2 id="what-s-new" tabindex="-1">What’s new? <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What’s new?&quot;">​</a></h2><p>Branch’s Apple Ads integration now includes:</p><ul><li><strong>AAK support</strong>: Attribution tracking using Apple’s Ad Attribution Kit framework for Apple Ads campaigns.</li><li><strong>Required configuration change</strong>: You must add AAK to your Info.plist in addition to SKAdNetwork to prevent service disruption.</li></ul><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><p>Adding AAK support enables you to maintain Apple Ads tracking when iOS 26.2 releases.</p><p>Also, SKAN will continue to function for users up to iOS 26.2, at which point SKAN postbacks will mirror AAK postbacks for iOS 26.2+ users.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>To use AAK with Branch, your account needs to have <a href="./ads-overview.html">Ads</a> enabled, which is part of our <a href="./products.html#performance">Performance product</a>.</p><p>For more information, please contact your Account Manager or <a href="https://branchdocs.app.link/apple-ads-to-sales" target="_blank" rel="noreferrer">reach out to our Sales team</a>.</p><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><p>To set up this configuration, you will need to:</p><ol><li>Include AAK in your Info.plist file in addition to SKAN. For more information, visit <a href="https://developer.apple.com/documentation/adattributionkit/configuring-an-advertised-app" target="_blank" rel="noreferrer">Apple’s guide</a>.</li><li>Deploy the updated app before iOS 26.2 releases (mid-December 2025).</li></ol><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Without this update, <strong>Apple Ads attribution will be interrupted</strong> for users on iOS 26.2 and later.</p></div><h2 id="availability" tabindex="-1">Availability <a class="header-anchor" href="#availability" aria-label="Permalink to &quot;Availability&quot;">​</a></h2><p>AAK support is currently available for Apple Ads campaigns only. Support for additional ad partners is forthcoming.</p><h2 id="more-information" tabindex="-1">More information <a class="header-anchor" href="#more-information" aria-label="Permalink to &quot;More information&quot;">​</a></h2><p>For more information on SKAN setup, visit <a href="./enable-skadnetwork.html">Enable SKAdNetwork</a>.</p><p>To learn more about Apple Ads, visit <a href="./enable-apple-ads.html">Enable Apple Ads</a>.</p>',20)])])}const h=a(r,[["render",n]]);export{A as __pageData,h as default};
